      // 2026-03-08 at noon EDT (UTC-4, 16:00 UTC) → next 7am is 2026-03-09 07:00 EDT = 11:00 UTC
      const boundary = getNextDayBoundary("America/New_York", "2026-03-08T16:00:00Z");
      expect(boundary).toBe("2026-03-09T11:00:00.000Z");
    });
