  });

  describe("advanceBoundary", () => {
    test("advances to the next 7am from current boundary", () => {
      const next = advanceBoundary("America/New_York", "2026-04-07T11:00:00.000Z");
      expect(next).toBe("2026-04-08T11:00:00.000Z");
