tool_input.content:
* { margin: 0; padding: 0; box-sizing: border-box; }

:root {
  --bg: #0f0f1a;
  --surface: #1a1a2e;
  --surface-2: #2d3748;
  --text: #e2e8f0;
  --text-dim: #718096;
  --primary: #3182ce;
  --success: #48bb78;
  --warning: #ecc94b;
  --danger: #fc8181;
  --radius: 10px;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  background: var(--bg);
  color: var(--text);
  min-height: 100dvh;
  -webkit-tap-highlight-color: transparent;
}

#app {
  max-width: 420px;
  margin: 0 auto;
  padding: 20px 16px;
  min-height: 100dvh;
}

.auth-screen {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 80dvh;
  gap: 24px;
}

.auth-screen .logo { font-size: 28px; font-weight: bold; text-align: center; }
.auth-screen .subtitle { font-size: 13px; color: var(--text-dim); margin-top: -16px; }

.auth-form { width: 100%; max-width: 300px; display: flex; flex-direction: column; gap: 16px; }

.input-group label {
  display: block; font-size: 11px; text-transform: uppercase;
  color: var(--text-dim); margin-bottom: 6px; letter-spacing: 0.5px;
}

.input-group input {
  width: 100%; padding: 12px 14px; background: var(--surface-2);
  border: none; border-radius: var(--radius); color: var(--text);
  font-size: 16px; outline: none;
}

.input-group input:focus { box-shadow: 0 0 0 2px var(--primary); }

.passcode-boxes { display: flex; gap: 10px; justify-content: center; }

.passcode-boxes input {
  width: 48px; height: 52px; text-align: center; font-size: 22px;
  background: var(--surface-2); border: none; border-radius: var(--radius);
  color: var(--text); outline: none; -moz-appearance: textfield;
}

.passcode-boxes input::-webkit-outer-spin-button,
.passcode-boxes input::-webkit-inner-spin-button { -webkit-appearance: none; margin: 0; }

.passcode-boxes input:focus { box-shadow: 0 0 0 2px var(--primary); }

.btn {
  padding: 14px; border: none; border-radius: var(--radius);
  font-size: 15px; font-weight: 600; cursor: pointer;
  text-align: center; transition: opacity 0.15s;
}
.btn:active { opacity: 0.8; }
.btn-primary { background: var(--primary); color: white; }
.btn-danger { background: var(--danger); color: #1a1a2e; }
.btn-surface { background: var(--surface-2); color: var(--text); }

.auth-toggle { font-size: 13px; color: var(--text-dim); text-align: center; }
.auth-toggle a { color: var(--primary); cursor: pointer; text-decoration: none; }

.error-msg { color: var(--danger); font-size: 13px; text-align: center; min-height: 20px; }

.dashboard-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
.greeting-sub { font-size: 13px; color: var(--text-dim); }
.greeting-name { font-size: 20px; font-weight: bold; }

.settings-btn {
  background: none; border: none; color: var(--text-dim);
  font-size: 18px; cursor: pointer; padding: 8px;
}

.progress-card {
  background: var(--surface); border-radius: var(--radius);
  padding: 20px; text-align: center; margin-bottom: 12px;
}
.progress-label { font-size: 11px; text-transform: uppercase; color: var(--text-dim); margin-bottom: 8px; }
