import { FilesetResolver, PoseLandmarker, DrawingUtils } from 'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.34/vision_bundle.mjs';

let poseLandmarker = null;
let animationFrameId = null;

const MIN_VISIBILITY = 0.5;
const SMOOTHING_WINDOW = 9;
const MIN_DIP_AMPLITUDE = 0.04;
// Elbow must bend below this angle at some point during descent to confirm a real pushup
const MAX_ELBOW_ANGLE_FOR_REP = 130;

export async function initPoseDetection() {
  if (poseLandmarker) return poseLandmarker;
  const vision = await FilesetResolver.forVisionTasks(
    'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.34/wasm'
  );
  poseLandmarker = await PoseLandmarker.createFromOptions(vision, {
    baseOptions: {
      modelAssetPath: 'https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_lite/float16/1/pose_landmarker_lite.task',
      delegate: 'GPU',
    },
    runningMode: 'VIDEO',
    numPoses: 1,
  });
  return poseLandmarker;
}

function calculateAngle(a, b, c) {
  const radians = Math.atan2(c.y - b.y, c.x - b.x) - Math.atan2(a.y - b.y, a.x - b.x);
  let angle = Math.abs(radians * 180 / Math.PI);
  if (angle > 180) angle = 360 - angle;
  return angle;
}

function smoothValue(buffer, newValue) {
  buffer.push(newValue);
  if (buffer.length > SMOOTHING_WINDOW) buffer.shift();
  return buffer.reduce((a, b) => a + b, 0) / buffer.length;
}

function getBestElbowAngle(landmarks) {
  const lVis = Math.min(landmarks[11].visibility, landmarks[13].visibility, landmarks[15].visibility);
  const rVis = Math.min(landmarks[12].visibility, landmarks[14].visibility, landmarks[16].visibility);
  let angle = null;
  let vis = 0;
  if (lVis > MIN_VISIBILITY) {
    angle = calculateAngle(landmarks[11], landmarks[13], landmarks[15]);
    vis = lVis;
  }
  if (rVis > MIN_VISIBILITY && rVis > lVis) {
    angle = calculateAngle(landmarks[12], landmarks[14], landmarks[16]);
    vis = rVis;
  }
  return { angle, vis };
}

export function startTracking(video, canvas, onCount, onDebug) {
  const ctx = canvas.getContext('2d');
  let count = 0;
  let tracking = false;
  let frameNum = 0;

  const noseYBuffer = [];
  const shoulderYBuffer = [];
  const elbowAngleBuffer = [];

  let phase = 'READY';
  let nosePeakY = 0;
  let noseBaselineY = 0;
  let shoulderBaselineY = 0;
  let shoulderPeakY = 0;
  let minElbowDuringDescent = 180;
  let wristYSamples = []; // track wrist positions during descent
  const MAX_WRIST_VARIANCE = 0.015; // wrists must stay planted (low movement)

  const eventLog = [];
  function logEvent(type, data) {
    eventLog.push({ t: (performance.now() / 1000).toFixed(2), frame: frameNum, type, ...data });
    if (eventLog.length > 200) eventLog.shift();
  }

  function processFrame() {
    if (!poseLandmarker || video.paused || video.ended) {
      animationFrameId = requestAnimationFrame(processFrame);
      return;
    }

    frameNum++;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    const result = poseLandmarker.detectForVideo(video, performance.now());
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (result.landmarks && result.landmarks.length > 0) {
      const landmarks = result.landmarks[0];
      tracking = true;

      const drawingUtils = new DrawingUtils(ctx);
      drawingUtils.drawLandmarks(landmarks, { radius: 3, color: '#48bb78', fillColor: '#48bb78' });
      drawingUtils.drawConnectors(landmarks, PoseLandmarker.POSE_CONNECTIONS, { color: '#3182ce', lineWidth: 2 });

      const nose = landmarks[0];
      const lShoulder = landmarks[11];
      const rShoulder = landmarks[12];
      const shoulderVis = Math.max(lShoulder.visibility, rShoulder.visibility);

      if (shoulderVis < MIN_VISIBILITY) {
        if (onDebug) onDebug({ noseY: 0, shoulderY: 0, elbowAngle: '--', minElbow: '--', noseDip: 0, shoulderDip: 0, phase, count, gated: 'low-vis' });
        animationFrameId = requestAnimationFrame(processFrame);
        return;
      }

      const rawShoulderY = (lShoulder.y + rShoulder.y) / 2;
      const smoothedShoulderY = smoothValue(shoulderYBuffer, rawShoulderY);

      const hasNose = nose.visibility > MIN_VISIBILITY;
      const rawNoseY = hasNose ? nose.y : rawShoulderY;
      const smoothedNoseY = smoothValue(noseYBuffer, rawNoseY);

      // Elbow angle (best visible side)
      const { angle: rawElbow } = getBestElbowAngle(landmarks);
      const elbowAngle = rawElbow !== null ? Math.round(smoothValue(elbowAngleBuffer, rawElbow)) : null;

      // Wrist y-position (average of visible wrists)
      const lWrist = landmarks[15];
      const rWrist = landmarks[16];
      let wristY = null;
      if (lWrist.visibility > MIN_VISIBILITY && rWrist.visibility > MIN_VISIBILITY) {
        wristY = (lWrist.y + rWrist.y) / 2;
      } else if (lWrist.visibility > MIN_VISIBILITY) {
        wristY = lWrist.y;
      } else if (rWrist.visibility > MIN_VISIBILITY) {
        wristY = rWrist.y;
      }

      if (noseBaselineY === 0) {
        noseBaselineY = smoothedNoseY;
        nosePeakY = smoothedNoseY;
        shoulderBaselineY = smoothedShoulderY;
        shoulderPeakY = smoothedShoulderY;
      }

      const noseDip = smoothedNoseY - noseBaselineY;
      const shoulderDip = smoothedShoulderY - shoulderBaselineY;
      const noseDipFromPeak = nosePeakY - smoothedNoseY;

      if (onDebug) {
        onDebug({
          noseY: smoothedNoseY.toFixed(3),
          shoulderY: smoothedShoulderY.toFixed(3),
          elbowAngle: elbowAngle !== null ? elbowAngle : '--',
          minElbow: phase !== 'READY' ? Math.round(minElbowDuringDescent) : '--',
          noseDip: noseDip.toFixed(3),
          shoulderDip: shoulderDip.toFixed(3),
          phase,
          count,
          gated: 'active',
        });
      }

      // Track during descent/ascent
      if (phase !== 'READY') {
        if (elbowAngle !== null && elbowAngle < minElbowDuringDescent) {
          minElbowDuringDescent = elbowAngle;
        }
        if (wristY !== null) {
          wristYSamples.push(wristY);
        }
      }

      if (phase === 'READY') {
        noseBaselineY = smoothedNoseY * 0.05 + noseBaselineY * 0.95;
        shoulderBaselineY = smoothedShoulderY * 0.05 + shoulderBaselineY * 0.95;
        if (noseDip > MIN_DIP_AMPLITUDE * 0.5) {
          phase = 'DESCENDING';
          nosePeakY = smoothedNoseY;
          shoulderPeakY = smoothedShoulderY;
          minElbowDuringDescent = elbowAngle !== null ? elbowAngle : 180;
          wristYSamples = [];
          logEvent('DESCEND', { nY: smoothedNoseY.toFixed(3), sY: smoothedShoulderY.toFixed(3), elbow: elbowAngle, wristY: wristY !== null ? wristY.toFixed(3) : null });
        }
      }

      if (phase === 'DESCENDING') {
        if (smoothedNoseY > nosePeakY) nosePeakY = smoothedNoseY;
        if (smoothedShoulderY > shoulderPeakY) shoulderPeakY = smoothedShoulderY;

        const noseTotalDip = nosePeakY - noseBaselineY;
        if (noseDipFromPeak > MIN_DIP_AMPLITUDE * 0.3 && noseTotalDip > MIN_DIP_AMPLITUDE) {
          const shoulderTotalDip = shoulderPeakY - shoulderBaselineY;

          // Four checks must pass:
          // 1. Shoulders also moved (not just head)
          // 2. Elbow angle dropped below threshold (arms actually bent)
          // 3. Wrists stayed planted (low variance = hands on floor)
          // 4. Wrist data was available
          const shoulderOk = shoulderTotalDip > MIN_DIP_AMPLITUDE * 0.5;
          const elbowOk = minElbowDuringDescent <= MAX_ELBOW_ANGLE_FOR_REP;
          const hasElbow = minElbowDuringDescent < 180;

          // Wrist variance: compute standard deviation of wrist y during descent
          let wristVar = 0;
          let wristOk = false;
          if (wristYSamples.length >= 3) {
            const mean = wristYSamples.reduce((a, b) => a + b, 0) / wristYSamples.length;
            wristVar = Math.sqrt(wristYSamples.reduce((sum, v) => sum + (v - mean) ** 2, 0) / wristYSamples.length);
            wristOk = wristVar <= MAX_WRIST_VARIANCE;
          }
          const hasWrist = wristYSamples.length >= 3;

          if (shoulderOk && elbowOk && wristOk) {
            phase = 'ASCENDING';
            logEvent('ASCEND', { noseDip: noseTotalDip.toFixed(3), shoulderDip: shoulderTotalDip.toFixed(3), minElbow: Math.round(minElbowDuringDescent), wristVar: wristVar.toFixed(4) });
          } else {
            const reason = !shoulderOk ? 'shoulder' : !hasElbow ? 'no-elbow-data' : !elbowOk ? 'elbow-too-straight' : !hasWrist ? 'no-wrist-data' : 'wrist-moved';
            logEvent('REJECT', { reason, noseDip: noseTotalDip.toFixed(3), shoulderDip: shoulderTotalDip.toFixed(3), minElbow: Math.round(minElbowDuringDescent), wristVar: wristVar.toFixed(4) });
            phase = 'READY';
            noseBaselineY = smoothedNoseY;
            nosePeakY = smoothedNoseY;
            shoulderBaselineY = smoothedShoulderY;
            shoulderPeakY = smoothedShoulderY;
          }
        }
      }

      if (phase === 'ASCENDING') {
        const noseTotalDip = nosePeakY - noseBaselineY;
        const noseReturn = nosePeakY - smoothedNoseY;
        if (noseReturn > noseTotalDip * 0.6) {
          count++;
          onCount(count);
          logEvent('COUNT', { n: count, noseDip: noseTotalDip.toFixed(3), minElbow: Math.round(minElbowDuringDescent) });
          phase = 'READY';
          noseBaselineY = smoothedNoseY;
          nosePeakY = smoothedNoseY;
          shoulderBaselineY = smoothedShoulderY;
          shoulderPeakY = smoothedShoulderY;
          minElbowDuringDescent = 180;
        }
      }
    } else {
      tracking = false;
      if (onDebug) onDebug({ noseY: 0, shoulderY: 0, elbowAngle: '--', minElbow: '--', noseDip: 0, shoulderDip: 0, phase, count, gated: 'no-pose' });
    }

    animationFrameId = requestAnimationFrame(processFrame);
  }

  animationFrameId = requestAnimationFrame(processFrame);

  return {
    getCount: () => count,
    isTracking: () => tracking,
    getLog: () => eventLog,
    stop: () => {
      if (animationFrameId) cancelAnimationFrame(animationFrameId);
      animationFrameId = null;
    },
  };
}

export async function getCamera(facingMode = 'user') {
  return navigator.mediaDevices.getUserMedia({
    video: { facingMode, width: { ideal: 1280 }, height: { ideal: 720 } },
    audio: false,
  });
}

let currentUser = null;
let currentScreen = 'loading';

let poseModule = null;
async function loadPose() {
  if (!poseModule) poseModule = await import('/pose.js');
  return poseModule;
}

async function api(method, path, body) {
  const opts = { method, headers: { 'content-type': 'application/json' }, credentials: 'same-origin' };
  if (body) opts.body = JSON.stringify(body);
  const res = await fetch(path, opts);
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || 'Request failed');
  return data;
}

function showToast(msg, duration = 3000) {
  const el = document.getElementById('toast');
  el.textContent = msg;
  el.classList.remove('hidden');
  setTimeout(() => el.classList.add('hidden'), duration);
}

function showScreen(name, data) {
  currentScreen = name;
  const app = document.getElementById('app');
  switch (name) {
    case 'auth': renderAuth(app); break;
    case 'dashboard': renderDashboard(app, data); break;
    case 'camera': renderCamera(app); break;
    case 'team': renderTeam(app); break;
    default: app.innerHTML = '<p>Loading...</p>';
  }
}

function renderAuth(app) {
  let mode = 'login';

  function render() {
    app.innerHTML = `
      <div class="auth-screen">
        <div class="logo">PushTracker</div>
        <div class="subtitle">Hold each other accountable</div>
        <form class="auth-form" id="auth-form">
          <div class="input-group">
            <label>Username</label>
            <input type="text" id="auth-username" autocomplete="username" autocapitalize="none" required>
          </div>
          <div class="input-group">
            <label>4-Digit Passcode</label>
            <div class="passcode-boxes">
              <input type="number" inputmode="numeric" maxlength="1" class="pin" data-idx="0">
              <input type="number" inputmode="numeric" maxlength="1" class="pin" data-idx="1">
              <input type="number" inputmode="numeric" maxlength="1" class="pin" data-idx="2">
              <input type="number" inputmode="numeric" maxlength="1" class="pin" data-idx="3">
            </div>
          </div>
          <div class="error-msg" id="auth-error"></div>
          <button type="submit" class="btn btn-primary">${mode === 'login' ? 'Log In' : 'Sign Up'}</button>
        </form>
        <div class="auth-toggle">
          ${mode === 'login'
            ? 'New here? <a id="toggle-auth">Sign up</a>'
            : 'Have an account? <a id="toggle-auth">Log in</a>'}
        </div>
      </div>
    `;

    const pins = app.querySelectorAll('.pin');
    pins.forEach((pin, i) => {
      pin.addEventListener('input', () => {
        pin.value = pin.value.slice(-1);
        if (pin.value && i < 3) pins[i + 1].focus();
      });
      pin.addEventListener('keydown', (e) => {
        if (e.key === 'Backspace' && !pin.value && i > 0) pins[i - 1].focus();
      });
    });

    app.querySelector('#toggle-auth').addEventListener('click', () => {
      mode = mode === 'login' ? 'signup' : 'login';
      render();
    });

    app.querySelector('#auth-form').addEventListener('submit', async (e) => {
      e.preventDefault();
      const username = app.querySelector('#auth-username').value.trim();
      const passcode = Array.from(pins).map(p => p.value).join('');
      const errEl = app.querySelector('#auth-error');

      if (passcode.length !== 4) {
        errEl.textContent = 'Enter a 4-digit passcode';
        return;
      }

      try {
        const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
        if (mode === 'signup') {
          const data = await api('POST', '/api/auth/signup', { username, passcode, timezone: tz });
          currentUser = data.user;
        } else {
          const data = await api('POST', '/api/auth/login', { username, passcode });
          currentUser = data.user;
        }
        await checkTimezone();
        await loadDashboard();
      } catch (err) {
        errEl.textContent = err.message;
      }
    });
  }

  render();
}

async function checkTimezone() {
  const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
  if (currentUser && currentUser.timezone !== tz) {
    const res = await api('PUT', '/api/me/timezone', { timezone: tz });
    if (res.changed) {
      currentUser.timezone = tz;
      showToast('We noticed you changed time zones \u2014 your daily reset has been updated.');
    }
  }
}

async function loadDashboard() {
  const data = await api('GET', '/api/me');
  currentUser = { ...currentUser, ...data };
  showScreen('dashboard', data);
}

function renderDashboard(app, data) {
  const pct = data.daily_target > 0 ? Math.min(100, (data.today_total / data.daily_target) * 100) : 0;

  app.innerHTML = `
    <div class="dashboard-header">
      <div>
        <div class="greeting-sub">Hey,</div>
        <div class="greeting-name">${data.username}</div>
      </div>
      <button class="settings-btn" id="settings-btn">&#9881;</button>
    </div>
    <div class="progress-card">
      <div class="progress-label">Today</div>
      <div class="progress-count">${data.today_total} <span class="progress-target">/ ${data.daily_target}</span></div>
      <div class="progress-bar"><div class="progress-fill" style="width:${pct}%"></div></div>
    </div>
    ${data.debt > 0 ? `
    <div class="debt-card">
      <div><div style="font-size:11px;text-transform:uppercase;color:var(--text-dim)">Debt</div><div class="debt-count">${data.debt}</div></div>
      <div class="debt-label">pushups<br>owed</div>
    </div>` : ''}
    <div class="action-buttons">
      <button class="action-btn primary" id="btn-camera">
        <span class="icon">&#128247;</span><span class="label">Camera</span>
      </button>
      <button class="action-btn" id="btn-manual">
        <span class="icon">&#9998;</span><span class="label">Manual</span>
      </button>
      <button class="action-btn" id="btn-team">
        <span class="icon">&#128101;</span><span class="label">Team</span>
      </button>
    </div>
  `;

  app.querySelector('#btn-camera').addEventListener('click', () => showScreen('camera'));
  app.querySelector('#btn-manual').addEventListener('click', () => showManualEntry());
  app.querySelector('#btn-team').addEventListener('click', () => showScreen('team'));
  app.querySelector('#settings-btn').addEventListener('click', () => showSettings());
}

function showManualEntry() {
  let count = 10;
  const overlay = document.createElement('div');
  overlay.className = 'manual-entry';
  overlay.innerHTML = `
    <div class="manual-card">
      <h3>Log Pushups</h3>
      <div class="stepper">
        <button id="step-down">\u2212</button>
        <div class="value" id="step-val">${count}</div>
        <button id="step-up">+</button>
      </div>
      <button class="btn btn-primary" style="width:100%;margin-bottom:10px" id="step-save">Save</button>
      <button class="btn btn-surface" style="width:100%" id="step-cancel">Cancel</button>
    </div>
  `;
  document.body.appendChild(overlay);

  const valEl = overlay.querySelector('#step-val');
  overlay.querySelector('#step-down').addEventListener('click', () => { count = Math.max(1, count - 5); valEl.textContent = count; });
  overlay.querySelector('#step-up').addEventListener('click', () => { count += 5; valEl.textContent = count; });
  overlay.querySelector('#step-cancel').addEventListener('click', () => overlay.remove());
  overlay.querySelector('#step-save').addEventListener('click', async () => {
    await api('POST', '/api/pushups', { count, source: 'manual' });
    overlay.remove();
    showToast(`Logged ${count} pushups`);
    await loadDashboard();
  });
}

function showSettings() {
  const overlay = document.createElement('div');
  overlay.className = 'settings-panel';
  overlay.innerHTML = `
    <div class="settings-card">
      <h3>Settings</h3>
      <div class="setting-row">
        <span class="setting-label">Daily Target</span>
        <div class="setting-value"><input type="number" id="set-target" value="${currentUser.daily_target}" inputmode="numeric"></div>
      </div>
      <div class="setting-row">
        <span class="setting-label">Timezone</span>
        <span style="font-size:13px;color:var(--text-dim)">${currentUser.timezone}</span>
      </div>
      <button class="btn btn-primary" style="width:100%;margin-top:16px;margin-bottom:10px" id="set-save">Save</button>
      <button class="btn btn-danger" style="width:100%;margin-bottom:10px" id="set-logout">Log Out</button>
      <button class="btn btn-surface" style="width:100%" id="set-close">Close</button>
    </div>
  `;
  document.body.appendChild(overlay);

  overlay.querySelector('#set-save').addEventListener('click', async () => {
    const target = parseInt(overlay.querySelector('#set-target').value) || 0;
    await api('PUT', '/api/me/target', { target });
    currentUser.daily_target = target;
    overlay.remove();
    showToast('Target updated');
    await loadDashboard();
  });
  overlay.querySelector('#set-logout').addEventListener('click', async () => {
    await api('POST', '/api/auth/logout');
    currentUser = null;
    overlay.remove();
    showScreen('auth');
  });
  overlay.querySelector('#set-close').addEventListener('click', () => overlay.remove());
  overlay.addEventListener('click', (e) => { if (e.target === overlay) overlay.remove(); });
}

async function renderTeam(app) {
  const team = await api('GET', '/api/team/today');
  team.sort((a, b) => {
    const aDone = a.daily_target > 0 && a.today_total >= a.daily_target;
    const bDone = b.daily_target > 0 && b.today_total >= b.daily_target;
    if (aDone !== bDone) return aDone ? 1 : -1;
    return a.username.localeCompare(b.username);
  });

  app.innerHTML = `
    <div class="team-screen">
      <div class="team-header">
        <h2>Team</h2>
        <button class="back-btn" id="back-dash">&larr; Back</button>
      </div>
      ${team.map(m => {
        let statusClass = 'not-started';
        let display = `${m.today_total} / ${m.daily_target}`;
        if (m.daily_target > 0 && m.today_total >= m.daily_target) {
          statusClass = 'complete';
          display = `${m.today_total} &#10004;`;
        } else if (m.today_total > 0) {
          statusClass = 'in-progress';
        }
        return `
          <div class="team-member">
            <div>
              <div class="member-name">${m.username}</div>
              <div class="member-target">Target: ${m.daily_target}</div>
              ${m.debt > 0 ? `<div class="member-debt">Debt: ${m.debt}</div>` : ''}
            </div>
            <div class="member-progress ${statusClass}">${display}</div>
          </div>`;
      }).join('')}
    </div>
  `;

  app.querySelector('#back-dash').addEventListener('click', () => loadDashboard());
}

